{"action":"tool_call","tool_name":"write_file","arguments":{"path":"src/env_assignments.py","content":"import re


_KEY_RE = re.compile(r"[A-Z_][A-Z0-9_]*", re.ASCII)


def _decode_quoted(value: str) -> str:
    result: list[str] = []
    index = 0
    escapes = {"\\": "\\", '"': '"', "n": "\n", "t": "\t"}
    while index < len(value):
        character = value[index]
        if character == '"':
            raise ValueError("unescaped quote")
        if character != "\\":
            result.append(character)
            index += 1
            continue
        if index + 1 >= len(value):
            raise ValueError("dangling escape")
        escaped = value[index + 1]
        if escaped not in escapes:
            raise ValueError("unknown escape")
        result.append(escapes[escaped])
        index += 2
    return "".join(result)


def parse_env_assignments(text: str) -> dict[str, str]:
    """Parse the declared deterministic assignment format."""
    if not isinstance(text, str):
        raise ValueError("input must be a string")
    result: dict[str, str] = {}
    for raw_line in text.splitlines():
        line = raw_line.strip(" \t")
        if not line or line.startswith("#"):
            continue
        if "=" not in line:
            raise ValueError("assignment is missing equals")
        raw_key, raw_value = line.split("=", 1)
        key = raw_key.strip(" \t")
        value = raw_value.strip(" \t")
        if _KEY_RE.fullmatch(key) is None:
            raise ValueError("invalid assignment key")
        if key in result:
            raise ValueError("duplicate assignment key")
        if value.startswith('"'):
            if len(value) < 2 or not value.endswith('"'):
                raise ValueError("unterminated quoted value")
            decoded = _decode_quoted(value[1:-1])
        else:
            if '"' in value:
                raise ValueError("stray quote in unquoted value")
            decoded = value
        result[key] = decoded
    return result
